import ast, pathlib
for fn in ['train.py','model.py','predict.py']:
    print('\n###',fn)
    txt=pathlib.Path(fn).read_text()
    tree=ast.parse(txt)
    for node in tree.body:
        if isinstance(node,(ast.FunctionDef,ast.ClassDef)):
            print(f'{node.__class__.__name__} {node.name} line {node.lineno}-{getattr(node,"end_lineno",None)}')
    if fn=='train.py':
        for i,line in enumerate(txt.splitlines(),1):
            if 'add_argument' in line or 'SSLDeepfakeDetector' in line or 'torch.save' in line or 'best' in line and 'pt' in line:
                print(f'{i:04d}: {line[:180]}')
    if fn=='predict.py':
        for i,line in enumerate(txt.splitlines(),1):
            if 'add_argument' in line or 'load' in line or 'SSLDeepfakeDetector' in line or 'autocast' in line or 'predictions' in line:
                print(f'{i:04d}: {line[:180]}')
